INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_ad7b5f5f4e70', '2025专利法模拟试卷A.pdf', 3, '请人以日本实用新型专利申请为优先权基础，通过国务院专利行政部门指定的特定电子系统以电子方式提交发明专利申请后，发现中国专利申请说明书附图提交错误，欲通过援引在先申请的方式补交说明书，下列说法正确的有：

