INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_0139edea7286', '2025专利法模拟试卷A.pdf', 21, '2022年10月21日。由于李某未在规定期限内提交在先申请文件副本，因此收到了国家知识产权局于2024年2月28日以邮寄的方式发出的视为未要求优先权通知书。现李某欲请求恢复权利，下列说法哪些是正确的？

