INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_a290f02ff666', '2025专利法模拟试卷A.pdf', 43, '# 4. 答案：B

解析：无效请求人提交回执表示参加但未到场，权利人未提交回执也未参加，合议组可直接作出审查决定；A 应继续审理，C 应直接决定，D 无效请求人中途退庭视为撤回，但题干未明确此情形。

