依据：《专利法》第22条', 107);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_a1cf3b539e79', '2025专利法模拟试卷A.pdf', 46, '# 7. 答案：C

