依据：《专利法》第26条', 76);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_146839621fd1', '2025专利法模拟试卷A.pdf', 55, '# 16. 答案: C

