依据：《专利法》第 33 条', 108);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_de131a856074', '2025专利法模拟试卷A.pdf', 57, '# 18. 答案: D

